using System.Runtime.InteropServices;

class EnvVarCheck
{
    void CheckFlag()
    {
        // On Linux, set via: export MY_FLAG=""
        // .NET 9 breaking change: on Unix, empty env vars now return null
        // instead of "". Use a P/Invoke to distinguish "not set" from "empty".
        var val = Environment.GetEnvironmentVariable("MY_FLAG");
        if (val == null && !IsEnvironmentVariableDefined("MY_FLAG"))
        {
            Console.WriteLine("MY_FLAG not set, using default");
        }
    }

    [DllImport("libc", EntryPoint = "getenv", CharSet = CharSet.Ansi)]
    private static extern IntPtr NativeGetEnv(string name);

    private static bool IsEnvironmentVariableDefined(string name)
    {
        return NativeGetEnv(name) != IntPtr.Zero;
    }
}

